export default App;

export type UnitId = 'unit1' | 'unit2' | 'unit3' | 'unit4' | 'unit5';
export type ViewMode = 'chat' | 'analysis';

export interface Message {
  id: string;
  role: 'user' | 'model';
  content: string;
  timestamp: number;
  isLoading?: boolean;
}

export interface Unit {
  id: UnitId;
  title: string;
  description: string;
  topics: string[];
}

export interface DataColumn {
  name: string;
  type: 'number' | 'string';
  data: (string | number)[];
}

export interface Dataset {
  name: string;
  columns: DataColumn[];
  rowCount: number;
}

export interface DescriptiveStats {
  column: string;
  mean?: number;
  median?: number;
  stdDev?: number;
  min?: number;
  max?: number;
  count: number;
  missing: number;
}

import { GoogleGenAI, ChatSession, GenerateContentResponse } from "@google/genai";
import { SYSTEM_INSTRUCTION } from '../constants';

let client: GoogleGenAI | null = null;
let chatSession: ChatSession | null = null;

const getClient = (): GoogleGenAI => {
  if (!client) {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      console.error("API Key not found in environment variables");
      throw new Error("API Key is missing. Please select one using the key selector if available.");
    }
    client = new GoogleGenAI({ apiKey });
  }
  return client;
};

export const initChat = async (unitContext: string): Promise<void> => {
  try {
    const ai = getClient();
    chatSession = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: `${SYSTEM_INSTRUCTION}\n\nContexto actual: El estudiante está consultando sobre: ${unitContext}`,
        temperature: 0.7,
      },
    });
  } catch (error) {
    console.error("Error initializing chat:", error);
  }
};

export const sendMessageToGemini = async (message: string, context?: string): Promise<string> => {
  try {
    if (!chatSession) {
      await initChat(context || "General");
    }

    if (!chatSession) {
        throw new Error("Failed to initialize chat session.");
    }

    // If context changed significantly, we might want to reinject it, but for now we keep the session flowing.
    // A more advanced implementation might recreate the session if the Unit changes drastically.

    const result: GenerateContentResponse = await chatSession.sendMessage({
      message: message
    });

    return result.text || "Lo siento, no pude generar una respuesta en este momento.";
  } catch (error) {
    console.error("Error sending message to Gemini:", error);
    return "Ocurrió un error al comunicarse con el servicio de IA. Por favor verifica tu conexión o intenta más tarde.";
  }
};

export const generateCodeSnippet = async (prompt: string, language: 'python' | 'r'): Promise<string> => {
    const ai = getClient();
    const result = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Genera un snippet de código en ${language} para: ${prompt}. 
        Asegúrate de incluir comentarios explicativos. 
        Usa librerías estándar como pandas/numpy para Python o base/tidyverse para R.
        Solo devuelve el código dentro de bloques markdown.`
    });
    return result.text || "";
}

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  icon?: React.ReactNode;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  icon,
  className = '',
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center rounded-lg font-medium transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-emerald-600 text-white hover:bg-emerald-700 focus:ring-emerald-500",
    secondary: "bg-slate-100 text-slate-900 hover:bg-slate-200 focus:ring-slate-500",
    outline: "border border-slate-300 bg-transparent text-slate-700 hover:bg-slate-50 focus:ring-emerald-500",
    ghost: "bg-transparent text-slate-600 hover:bg-slate-100 hover:text-slate-900 focus:ring-slate-500",
  };

  const sizes = {
    sm: "h-8 px-3 text-sm",
    md: "h-10 px-4 text-sm",
    lg: "h-12 px-6 text-base",
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`}
      {...props}
    >
      {icon && <span className="mr-2">{icon}</span>}
      {children}
    </button>
  );
};

