import React, { useState, useEffect, useRef } from 'react';
import { UnitId, Message } from '../types';
import { UNITS } from '../constants';
import { initChat, sendMessageToGemini } from '../services/geminiService';
import { Send, Bot, User, Loader2, RefreshCw } from 'lucide-react';
import ReactMarkdown from 'react-markdown';

interface ChatInterfaceProps {
  currentUnit: UnitId;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ currentUnit }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const unitInfo = UNITS.find(u => u.id === currentUnit);

  // Initialize chat when unit changes
  useEffect(() => {
    const initialize = async () => {
      setMessages([{
        id: 'welcome',
        role: 'model',
        content: `Hola, soy tu EstadísticaBot. Estoy aquí para ayudarte con la **${unitInfo?.title}**.\n\nTemas clave: ${unitInfo?.topics.join(', ')}. \n\n¿En qué puedo orientarte hoy?`,
        timestamp: Date.now()
      }]);
      await initChat(unitInfo?.title || "Estadística General");
    };
    initialize();
  }, [currentUnit, unitInfo]);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSendMessage = async () => {
    if (!inputValue.trim() || isLoading) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: inputValue,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setIsLoading(true);

    try {
      const responseText = await sendMessageToGemini(userMsg.content, unitInfo?.title);
      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        content: responseText,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50">
      {/* Unit Header context */}
      <div className="bg-white border-b border-slate-200 px-6 py-3 flex justify-between items-center shadow-sm z-10">
        <div>
          <h2 className="font-semibold text-slate-800">{unitInfo?.title}</h2>
          <p className="text-xs text-slate-500 truncate max-w-md">{unitInfo?.description}</p>
        </div>
        <button 
          onClick={() => {
            setMessages([]);
            initChat(unitInfo?.title || "General");
          }}
          className="text-slate-400 hover:text-emerald-600 transition-colors"
          title="Reiniciar chat"
        >
          <RefreshCw size={18} />
        </button>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6">
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex items-start gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}
          >
            <div className={`
              w-8 h-8 rounded-full flex items-center justify-center shrink-0
              ${msg.role === 'model' ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-200 text-slate-700'}
            `}>
              {msg.role === 'model' ? <Bot size={18} /> : <User size={18} />}
            </div>

            <div className={`
              max-w-[85%] md:max-w-[75%] rounded-2xl px-5 py-3.5 text-sm leading-relaxed shadow-sm
              ${msg.role === 'model' 
                ? 'bg-white border border-slate-200 text-slate-800' 
                : 'bg-emerald-600 text-white'}
            `}>
              {msg.role === 'model' ? (
                <div className="prose prose-sm max-w-none prose-emerald">
                  <ReactMarkdown>{msg.content}</ReactMarkdown>
                </div>
              ) : (
                <p className="whitespace-pre-wrap">{msg.content}</p>
              )}
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex items-start gap-4">
             <div className="w-8 h-8 rounded-full bg-emerald-100 text-emerald-700 flex items-center justify-center shrink-0">
               <Bot size={18} />
             </div>
             <div className="bg-white border border-slate-200 rounded-2xl px-5 py-4 shadow-sm">
                <div className="flex space-x-2">
                  <div className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
                  <div className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></div>
                  <div className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></div>
                </div>
             </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="bg-white p-4 border-t border-slate-200">
        <div className="max-w-4xl mx-auto relative flex items-end gap-2 bg-slate-50 border border-slate-300 rounded-xl p-2 focus-within:ring-2 focus-within:ring-emerald-500 focus-within:border-emerald-500 transition-all shadow-sm">
          <textarea
            className="flex-1 bg-transparent border-none focus:ring-0 resize-none max-h-32 min-h-[24px] py-2 px-2 text-slate-800 placeholder-slate-400 text-sm"
            placeholder="Escribe tu consulta o pega un problema aquí..."
            rows={1}
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyDown={handleKeyDown}
            style={{ height: 'auto', minHeight: '44px' }}
          />
          <button
            onClick={handleSendMessage}
            disabled={!inputValue.trim() || isLoading}
            className={`
              p-2 rounded-lg mb-0.5 transition-all
              ${!inputValue.trim() || isLoading 
                ? 'bg-slate-200 text-slate-400 cursor-not-allowed' 
                : 'bg-emerald-600 text-white hover:bg-emerald-700 shadow-sm'}
            `}
          >
            {isLoading ? <Loader2 size={18} className="animate-spin" /> : <Send size={18} />}
          </button>
        </div>
        <p className="text-center text-xs text-slate-400 mt-2">
          La IA puede cometer errores. Verifica la información con la bibliografía de la cátedra.
        </p>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { Upload, FileText, AlertCircle, BarChart, Activity, Table as TableIcon } from 'lucide-react';
import { Dataset, DescriptiveStats } from '../types';
import { Button } from './Button';
import { 
  BarChart as RechartsBar, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  Legend, 
  ResponsiveContainer,
  ScatterChart,
  Scatter,
  ZAxis
} from 'recharts';

export const DataAnalysis: React.FC = () => {
  const [dataset, setDataset] = useState<Dataset | null>(null);
  const [stats, setStats] = useState<DescriptiveStats[]>([]);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const calculateStats = (data: Dataset) => {
    const newStats: DescriptiveStats[] = [];

    data.columns.forEach(col => {
      if (col.type === 'number') {
        const numericValues = col.data.filter(v => typeof v === 'number' && !isNaN(v)) as number[];
        const count = numericValues.length;
        const missing = col.data.length - count;

        if (count > 0) {
          const sum = numericValues.reduce((a, b) => a + b, 0);
          const mean = sum / count;

          const sorted = [...numericValues].sort((a, b) => a - b);
          const min = sorted[0];
          const max = sorted[sorted.length - 1];
          const median = count % 2 === 0 
            ? (sorted[count/2 - 1] + sorted[count/2]) / 2 
            : sorted[Math.floor(count/2)];

          // Std Dev
          const squaredDiffs = numericValues.map(v => Math.pow(v - mean, 2));
          const avgSquaredDiff = squaredDiffs.reduce((a, b) => a + b, 0) / (count - 1); // Sample std dev
          const stdDev = Math.sqrt(avgSquaredDiff);

          newStats.push({
            column: col.name,
            mean,
            median,
            stdDev,
            min,
            max,
            count,
            missing
          });
        }
      }
    });
    setStats(newStats);
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    if (!file.name.endsWith('.csv')) {
      setError('Por favor sube un archivo CSV válido.');
      return;
    }

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const text = e.target?.result as string;
        const lines = text.split('\n').map(l => l.trim()).filter(l => l);
        if (lines.length < 2) throw new Error("El archivo está vacío o no tiene datos.");

        const headers = lines[0].split(',').map(h => h.trim());
        const rows = lines.slice(1).map(line => line.split(',').map(c => c.trim()));

        const columns = headers.map((header, index) => {
          const rawData = rows.map(r => r[index]);
          // Simple type inference
          const isNumber = rawData.every(v => v === '' || !isNaN(parseFloat(v)));
          const parsedData = rawData.map(v => isNumber && v !== '' ? parseFloat(v) : v);

          return {
            name: header,
            type: isNumber ? 'number' : 'string',
            data: parsedData
          };
        });

        const newDataset = {
          name: file.name,
          columns: columns as any,
          rowCount: rows.length
        };

        setDataset(newDataset);
        calculateStats(newDataset);
        setError(null);
      } catch (err) {
        setError("Error al procesar el archivo CSV. Asegúrate de que el formato sea correcto.");
        console.error(err);
      }
    };
    reader.readAsText(file);
  };

  const getHistogramData = (colName: string) => {
    if (!dataset) return [];
    const col = dataset.columns.find(c => c.name === colName);
    if (!col || col.type !== 'number') return [];

    const values = col.data.filter(v => typeof v === 'number') as number[];
    if (values.length === 0) return [];

    const min = Math.min(...values);
    const max = Math.max(...values);
    const bins = 10;
    const binWidth = (max - min) / bins;

    const histogram = Array.from({ length: bins }, (_, i) => {
      const start = min + i * binWidth;
      const end = min + (i + 1) * binWidth;
      const count = values.filter(v => v >= start && (i === bins - 1 ? v <= end : v < end)).length;
      return {
        range: `${start.toFixed(1)} - ${end.toFixed(1)}`,
        count
      };
    });
    return histogram;
  };

  return (
    <div className="h-full flex flex-col bg-slate-50 overflow-y-auto">
      {/* Header / Upload Section */}
      <div className="bg-white p-6 border-b border-slate-200">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
              <Activity className="text-emerald-600" />
              Estadística Descriptiva
            </h2>
            <p className="text-slate-500 text-sm mt-1">Sube tu archivo .csv para obtener un reporte automático.</p>
          </div>
          <div className="flex gap-2">
            <input 
              type="file" 
              accept=".csv" 
              ref={fileInputRef} 
              onChange={handleFileUpload} 
              className="hidden" 
            />
            <Button 
              variant="primary" 
              icon={<Upload size={16} />}
              onClick={() => fileInputRef.current?.click()}
            >
              Cargar CSV
            </Button>
            {dataset && (
               <Button 
               variant="outline" 
               onClick={() => {
                 setDataset(null);
                 setStats([]);
               }}
             >
               Limpiar
             </Button>
            )}
          </div>
        </div>

        {error && (
