import React, { useState, useEffect, useRef } from 'react';
import { UnitId, Message } from '../types';
import { UNITS } from '../constants';
import { initChat, sendMessageToGemini } from '../services/geminiService';
import { Send, Bot, User, Loader2, RefreshCw, Sparkles } from 'lucide-react';
import ReactMarkdown from 'react-markdown';

interface ChatInterfaceProps {
  currentUnit: UnitId;
  initialMessage?: string;
  onMessageSent?: () => void;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ currentUnit, initialMessage, onMessageSent }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const unitInfo = UNITS.find(u => u.id === currentUnit);

  // Initialize chat when unit changes
  useEffect(() => {
    const initialize = async () => {
      setMessages([{
        id: 'welcome',
        role: 'model',
        content: `Hola, soy tu EstadísticaBot. Estoy aquí para ayudarte con la **${unitInfo?.title}**.\n\n¿En qué puedo orientarte hoy?`,
        timestamp: Date.now()
      }]);
      await initChat(unitInfo?.title || "Estadística General");
    };
    initialize();
  }, [currentUnit, unitInfo]);

  // Handle initial message from Examples tab
  useEffect(() => {
    if (initialMessage) {
      setInputValue(initialMessage);
    }
  }, [initialMessage]);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSendMessage = async (text: string = inputValue) => {
    if (!text.trim() || isLoading) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    if (onMessageSent) onMessageSent();
    setIsLoading(true);

    try {
      const responseText = await sendMessageToGemini(userMsg.content, unitInfo?.title);
      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        content: responseText,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50">
      {/* Unit Header context */}
      <div className="bg-white border-b border-slate-200 px-6 py-3 flex justify-between items-center shadow-sm z-10">
        <div>
          <h2 className="font-semibold text-slate-800">{unitInfo?.title}</h2>
          <p className="text-xs text-slate-500 truncate max-w-md">{unitInfo?.description}</p>
        </div>
        <button 
          onClick={() => {
            setMessages([]);
            initChat(unitInfo?.title || "General");
          }}
          className="text-slate-400 hover:text-emerald-600 transition-colors"
          title="Reiniciar chat"
        >
          <RefreshCw size={18} />
        </button>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6">
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex items-start gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}
          >
            <div className={`
              w-8 h-8 rounded-full flex items-center justify-center shrink-0
              ${msg.role === 'model' ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-200 text-slate-700'}
            `}>
              {msg.role === 'model' ? <Bot size={18} /> : <User size={18} />}
            </div>

            <div className={`
              max-w-[85%] md:max-w-[75%] rounded-2xl px-5 py-3.5 text-sm leading-relaxed shadow-sm
              ${msg.role === 'model' 
                ? 'bg-white border border-slate-200 text-slate-800' 
                : 'bg-emerald-600 text-white'}
            `}>
              {msg.role === 'model' ? (
                <div className="prose prose-sm max-w-none prose-emerald">
                  <ReactMarkdown>{msg.content}</ReactMarkdown>
                </div>
              ) : (
                <p className="whitespace-pre-wrap">{msg.content}</p>
              )}
            </div>
          </div>
        ))}

        {/* Suggested Topics - Show only if messages length is 1 (Welcome message) */}
        {messages.length === 1 && unitInfo?.topics && (
          <div className="pl-12 pr-4 animate-fade-in">
             <div className="flex items-center gap-2 mb-3 text-xs font-semibold text-slate-400 uppercase tracking-wider">
               <Sparkles size={14} />
               <span>Temas Sugeridos</span>
             </div>
             <div className="flex flex-wrap gap-2">
                {unitInfo.topics.map((topic, idx) => (
                  <button
                    key={idx}
                    onClick={() => handleSendMessage(`Explícame sobre: ${topic} en el contexto de la unidad.`)}
                    className="bg-white border border-emerald-200 text-emerald-700 px-3 py-1.5 rounded-full text-xs hover:bg-emerald-50 hover:border-emerald-300 transition-colors shadow-sm"
                  >
                    {topic}
                  </button>
                ))}
             </div>
          </div>
        )}

        {isLoading && (
          <div className="flex items-start gap-4">
             <div className="w-8 h-8 rounded-full bg-emerald-100 text-emerald-700 flex items-center justify-center shrink-0">
               <Bot size={18} />
             </div>
             <div className="bg-white border border-slate-200 rounded-2xl px-5 py-4 shadow-sm">
                <div className="flex space-x-2">
                  <div className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
                  <div className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></div>
                  <div className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></div>
                </div>
             </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="bg-white p-4 border-t border-slate-200">
        <div className="max-w-4xl mx-auto relative flex items-end gap-2 bg-slate-50 border border-slate-300 rounded-xl p-2 focus-within:ring-2 focus-within:ring-emerald-500 focus-within:border-emerald-500 transition-all shadow-sm">
          <textarea
            className="flex-1 bg-transparent border-none focus:ring-0 resize-none max-h-32 min-h-[24px] py-2 px-2 text-slate-800 placeholder-slate-400 text-sm"
            placeholder="Escribe tu consulta o pega un problema aquí..."
            rows={1}
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyDown={handleKeyDown}
            style={{ height: 'auto', minHeight: '44px' }}
          />
          <button
            onClick={() => handleSendMessage()}
            disabled={!inputValue.trim() || isLoading}
            className={`
              p-2 rounded-lg mb-0.5 transition-all
              ${!inputValue.trim() || isLoading 
                ? 'bg-slate-200 text-slate-400 cursor-not-allowed' 
                : 'bg-emerald-600 text-white hover:bg-emerald-700 shadow-sm'}
            `}
          >
            {isLoading ? <Loader2 size={18} className="animate-spin" /> : <Send size={18} />}
          </button>
        </div>
        <p className="text-center text-xs text-slate-400 mt-2">
          La IA puede cometer errores. Verifica la información con la bibliografía de la cátedra.
        </p>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { Upload, FileText, AlertCircle, BarChart, Activity, Table as TableIcon, Edit3, Calculator } from 'lucide-react';
import { Dataset, DescriptiveStats } from '../types';
import { Button } from './Button';
import { 
  BarChart as RechartsBar, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer
} from 'recharts';

type InputMode = 'csv' | 'manual';

export const DataAnalysis: React.FC = () => {
  const [inputMode, setInputMode] = useState<InputMode>('csv');
  const [dataset, setDataset] = useState<Dataset | null>(null);
  const [stats, setStats] = useState<DescriptiveStats[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [manualInput, setManualInput] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Helper for advanced stats
  const calculateAdvancedStats = (numericValues: number[]): Partial<DescriptiveStats> => {
      const count = numericValues.length;
      if (count === 0) return {};

      const sum = numericValues.reduce((a, b) => a + b, 0);
      const mean = sum / count;
      const sorted = [...numericValues].sort((a, b) => a - b);
      const min = sorted[0];
      const max = sorted[count - 1];
      const range = max - min;

      // Median
      const median = count % 2 === 0 
        ? (sorted[count/2 - 1] + sorted[count/2]) / 2 
        : sorted[Math.floor(count/2)];

      // Variance (Sample) & StdDev
      const squaredDiffs = numericValues.map(v => Math.pow(v - mean, 2));
      const variance = count > 1 ? squaredDiffs.reduce((a, b) => a + b, 0) / (count - 1) : 0;
      const stdDev = Math.sqrt(variance);

      // Mode
      const freq: Record<number, number> = {};
      numericValues.forEach(v => freq[v] = (freq[v] || 0) + 1);
      const maxFreq = Math.max(...Object.values(freq));
      const modes = Object.keys(freq).filter(k => freq[parseFloat(k)] === maxFreq);
      const modeStr = modes.length === count ? "No hay moda" : modes.slice(0, 5).join(", ") + (modes.length > 5 ? "..." : "");

      // Quartiles
      const q1Pos = (count + 1) * 0.25;
      const q3Pos = (count + 1) * 0.75;

      const getQuantile = (pos: number) => {
        const base = Math.floor(pos) - 1;
        const rest = pos - Math.floor(pos);
        if (base < 0) return sorted[0];
        if (base >= count - 1) return sorted[count - 1];
        return sorted[base] + rest * (sorted[base + 1] - sorted[base]);
      };

      const q1 = getQuantile(q1Pos);
      const q3 = getQuantile(q3Pos);
      const iqr = q3 - q1;

      return { mean, median, min, max, stdDev, variance, mode: modeStr, range, q1, q3, iqr };
  };

  const calculateStats = (data: Dataset) => {
    const newStats: DescriptiveStats[] = [];

    data.columns.forEach(col => {
      if (col.type === 'number') {
        const numericValues = col.data.filter(v => typeof v === 'number' && !isNaN(v)) as number[];
        const count = numericValues.length;
        const missing = col.data.length - count;

        if (count > 0) {
          const advStats = calculateAdvancedStats(numericValues);

          newStats.push({
            column: col.name,
            count,
            missing,
            mean: advStats.mean,
            median: advStats.median,
            stdDev: advStats.stdDev,
            min: advStats.min,
            max: advStats.max,
            mode: advStats.mode,
            variance: advStats.variance,
            range: advStats.range,
            q1: advStats.q1,
            q3: advStats.q3,
            iqr: advStats.iqr
          });
        }
      }
    });
    setStats(newStats);
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    if (!file.name.endsWith('.csv')) {
      setError('Por favor sube un archivo CSV válido.');
      return;
    }

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const text = e.target?.result as string;
        const lines = text.split('\n').map(l => l.trim()).filter(l => l);
        if (lines.length < 2) throw new Error("El archivo está vacío o no tiene datos.");

        const headers = lines[0].split(',').map(h => h.trim());
        const rows = lines.slice(1).map(line => line.split(',').map(c => c.trim()));

        const columns = headers.map((header, index) => {
          const rawData = rows.map(r => r[index]);
          const isNumber = rawData.every(v => v === '' || !isNaN(parseFloat(v)));
          const parsedData = rawData.map(v => isNumber && v !== '' ? parseFloat(v) : v);

          return {
            name: header,
            type: isNumber ? 'number' : 'string',
            data: parsedData
          };
        });

        const newDataset = {
          name: file.name,
          columns: columns as any,
          rowCount: rows.length
        };

        setDataset(newDataset);
        calculateStats(newDataset);
        setError(null);
      } catch (err) {
        setError("Error al procesar el archivo CSV. Asegúrate de que el formato sea correcto.");
        console.error(err);
      }
    };
    reader.readAsText(file);
  };

  const handleManualAnalysis = () => {
      const values = manualInput
        .split(/[\s,;\n\t]+/)
        .map(s => s.trim())
        .filter(s => s !== "")
        .map(Number)
        .filter(n => !isNaN(n));

      if (values.length < 2) {
          setError("Por favor ingresa al menos 2 valores numéricos válidos.");
          return;
      }

      const newDataset: Dataset = {
          name: "Datos Manuales",
          rowCount: values.length,
          columns: [{
              name: "Variable X",
              type: 'number',
              data: values
          }]
      };

      setDataset(newDataset);
      calculateStats(newDataset);
      setError(null);
  };

  const getHistogramData = (colName: string) => {
    if (!dataset) return [];
    const col = dataset.columns.find(c => c.name === colName);
    if (!col || col.type !== 'number') return [];

    const values = col.data.filter(v => typeof v === 'number') as number[];
    if (values.length === 0) return [];

    const min = Math.min(...values);
    const max = Math.max(...values);
    const bins = 10;
    const binWidth = (max - min) / bins || 1;

    const histogram = Array.from({ length: bins }, (_, i) => {
      const start = min + i * binWidth;
      const end = min + (i + 1) * binWidth;
      const count = values.filter(v => v >= start && (i === bins - 1 ? v <= end : v < end)).length;
      return {
        range: `${start.toFixed(1)} - ${end.toFixed(1)}`,
        count
      };
    });
    return histogram;
  };

  return (
    <div className="h-full flex flex-col bg-slate-50 overflow-y-auto">
      {/* Header / Input Section */}
      <div className="bg-white p-6 border-b border-slate-200">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-4">
          <div>
            <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
              <Activity className="text-emerald-600" />
              Estadística Descriptiva
            </h2>
            <p className="text-slate-500 text-sm mt-1">
               {inputMode === 'csv' ? 'Sube tu archivo .csv' : 'Pega tus datos numéricos'} para obtener un reporte completo.
            </p>
          </div>
          <div className="flex bg-slate-100 p-1 rounded-lg">
             <button
               onClick={() => { setInputMode('csv'); setDataset(null); setError(null); }}
               className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${inputMode === 'csv' ? 'bg-white text-emerald-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
             >
               <div className="flex items-center gap-2"><Upload size={14} /> Subir CSV</div>
             </button>
             <button
               onClick={() => { setInputMode('manual'); setDataset(null); setError(null); }}
               className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${inputMode === 'manual' ? 'bg-white text-emerald-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
             >
                <div className="flex items-center gap-2"><Edit3 size={14} /> Entrada Manual</div>
             </button>
          </div>
        </div>

        {/* INPUT MODE: CSV */}
        {inputMode === 'csv' && (
             <div className="flex gap-2">
                <input type="file" accept=".csv" ref={fileInputRef} onChange={handleFileUpload} className="hidden" />
                <Button variant="primary" icon={<Upload size={16} />} onClick={() => fileInputRef.current?.click()}>
                Cargar CSV
                </Button>
                {dataset && (
                    <Button variant="outline" onClick={() => { setDataset(null); setStats([]); }}>Limpiar</Button>
                )}
            </div>
        )}

        {/* INPUT MODE: MANUAL */}
        {inputMode === 'manual' && (
             <div className="w-full">
                <textarea
                  className="w-full p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 font-mono text-sm"
                  rows={3}
                  placeholder="Ej: 12.5, 14.2, 11.8, 15.6, 13.0 (Separados por coma o espacio)"
                  value={manualInput}
                  onChange={(e) => setManualInput(e.target.value)}
                />
                <div className="mt-2 flex gap-2">
                   <Button variant="primary" icon={<Calculator size={16} />} onClick={handleManualAnalysis}>Calcular</Button>
                   {dataset && (
                     <Button variant="outline" onClick={() => { setDataset(null); setStats([]); setManualInput(''); }}>Limpiar</Button>
                   )}
                </div>
             </div>
        )}

        {error && (
          <div className="mt-4 p-3 bg-red-50 text-red-700 rounded-lg flex items-center text-sm">
            <AlertCircle size={16} className="mr-2" />
            {error}
          </div>
        )}

        {dataset && inputMode === 'csv' && (
          <div className="mt-4 flex items-center gap-2 text-sm text-emerald-700 bg-emerald-50 p-2 rounded-md border border-emerald-100 inline-flex">
            <FileText size={16} />
            <span className="font-semibold">{dataset.name}</span>
            <span className="text-emerald-600">({dataset.rowCount} filas)</span>
          </div>
        )}
      </div>

      {/* Results Section */}
      {dataset && stats.length > 0 ? (
        <div className="p-6 space-y-8">

          {/* Summary Table */}
          <section>
            <h3 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <TableIcon size={18} /> Resumen Estadístico
            </h3>
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-x-auto">
              <table className="w-full text-sm text-left">
                <thead className="bg-slate-50 text-slate-600 font-medium border-b border-slate-200">
                  <tr>
                    <th className="px-4 py-3 min-w-[100px]">Variable</th>
                    <th className="px-4 py-3">N</th>
                    <th className="px-4 py-3">Media</th>
                    <th className="px-4 py-3">Mediana</th>
                    <th className="px-4 py-3">Moda</th>
                    <th className="px-4 py-3">Desv. Est.</th>
                    <th className="px-4 py-3">Varianza</th>
                    <th className="px-4 py-3">Mín</th>
                    <th className="px-4 py-3">Máx</th>
                    <th className="px-4 py-3">Rango</th>
                    <th className="px-4 py-3">Q1 / Q3</th>
                    <th className="px-4 py-3">IQR</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {stats.map((s) => (
                    <tr key={s.column} className="hover:bg-slate-50">
                      <td className="px-4 py-3 font-medium text-slate-800">{s.column}</td>
                      <td className="px-4 py-3 text-slate-600">{s.count}</td>
                      <td className="px-4 py-3 font-mono text-emerald-700 font-medium">{s.mean?.toFixed(2)}</td>
                      <td className="px-4 py-3 font-mono text-slate-600">{s.median?.toFixed(2)}</td>
                      <td className="px-4 py-3 font-mono text-slate-500 text-xs truncate max-w-[100px]" title={s.mode}>{s.mode}</td>
                      <td className="px-4 py-3 font-mono text-slate-600">{s.stdDev?.toFixed(2)}</td>
                      <td className="px-4 py-3 font-mono text-slate-500 text-xs">{s.variance?.toFixed(2)}</td>
                      <td className="px-4 py-3 font-mono text-slate-600">{s.min}</td>
                      <td className="px-4 py-3 font-mono text-slate-600">{s.max}</td>
                      <td className="px-4 py-3 font-mono text-slate-500">{s.range?.toFixed(2)}</td>
