          <section className="bg-slate-900 text-slate-300 rounded-xl p-6">
            <h4 className="text-white font-semibold mb-2">💡 Tip para tu Informe</h4>
            <p className="text-sm mb-4">
              Código Python (pandas) para generar este reporte:
            </p>
            <pre className="bg-slate-950 p-4 rounded-lg overflow-x-auto text-xs font-mono text-emerald-400">
{`import pandas as pd
import numpy as np

# Datos simulados basados en tu entrada
data = [${dataset.columns[0].data.slice(0, 5).join(', ')}...] 
df = pd.DataFrame(data, columns=['${stats[0]?.column || 'Valor'}'])

# Estadísticas completas
